import React from 'react';
import EnrollmentForm from './EnrollmentForm';
import RecognizeView from './RecognizeView';
import AdminDashboard from './AdminDashboard';

function App() {
    return (
        <div className="App">
            <h1>Face Recognition Service</h1>
            <EnrollmentForm />
            <RecognizeView />
            <AdminDashboard />
        </div>
    );
}

export default App;
